```
from chatterbot.logic import LogicAdapter
from chatterbot.conversation import Statement
import location_details
import random
import pdb

class MyCustomAdapter1(LogicAdapter):

	def __init__(self, **kwargs):
		super().__init__(**kwargs)

	def can_process(self, statement):

		words = ["Hello", "Hi", "Hey" ]
		if any(word in statement.text.lower().split() for word in words):
			return True
		else:
			return False


	def process(self, statement):
		responses = ["Hello", "Hi there!", "How are you"]
		confidence = 1
		response_statement = (Statement(random.choice(responses)))
		return confidence, response_statement

```

